BEGIN;

-- ----- 1. Prospects table -----
CREATE TABLE IF NOT EXISTS prospects (
    id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
    tenant_id TEXT NOT NULL,
    company_name TEXT NOT NULL,
    ein TEXT,
    state TEXT,
    pbm TEXT,
    plan_type TEXT,
    employees INTEGER,
    annual_drug_spend DECIMAL(15,2),
    estimated_spread_overpayment DECIMAL(15,2),
    cfo_email TEXT,
    chro_email TEXT,
    form_5500_year INTEGER,
    source TEXT DEFAULT 'form_5500',
    created_at TIMESTAMPTZ DEFAULT NOW()
);
CREATE INDEX IF NOT EXISTS idx_prospects_tenant ON prospects(tenant_id);
CREATE INDEX IF NOT EXISTS idx_prospects_pbm ON prospects(pbm);
CREATE INDEX IF NOT EXISTS idx_prospects_overpayment ON prospects(estimated_spread_overpayment DESC);

-- ----- 2. Reset tenant_costplus seed data (idempotent) -----
DELETE FROM prospects WHERE tenant_id = 'tenant_costplus';
DELETE FROM conversations WHERE tenant_id = 'tenant_costplus';
DELETE FROM tasks WHERE tenant_id = 'tenant_costplus';
DELETE FROM reports WHERE tenant_id = 'tenant_costplus';
DELETE FROM pricing_snapshots WHERE captured_at > NOW() - INTERVAL '14 days' AND drug_name IN ('atorvastatin', 'metformin', 'lisinopril', 'omeprazole', 'sertraline', 'gabapentin', 'levothyroxine', 'losartan', 'amlodipine', 'simvastatin', 'bupropion XL', 'escitalopram', 'hydrochlorothiazide', 'montelukast', 'pantoprazole', 'rosuvastatin', 'trazodone', 'fluoxetine', 'citalopram', 'tamsulosin');

