INSERT INTO reports (report_id, tenant_id, query, summary, drugs_json, recommendation, total_annual_savings, generated_at) VALUES ('rep_c225f1137a03', 'tenant_costplus', 'Spread analysis for Acme Manufacturing — 850 self-insured employees, currently with CVS Caremark', 'Acme Manufacturing''s PBM contract with CVS Caremark shows aggregate spread of 2,940% above NADAC across the top-5 drug spend. Modeled annual overpayment: $1,142,400 across 850 covered lives. Switch to Cost Plus pass-through pricing recommended.', '[{"drug": "atorvastatin 20mg", "quantity": 30, "plan_charge": 86.4, "nadac": 1.48, "spread_pct": 5737.8, "tier": "CRITICAL", "estimated_annual_overpayment": 20380.8}, {"drug": "metformin 500mg", "quantity": 30, "plan_charge": 41.5, "nadac": 1.04, "spread_pct": 3890.4, "tier": "CRITICAL", "estimated_annual_overpayment": 9710.4}, {"drug": "lisinopril 10mg", "quantity": 30, "plan_charge": 38.2, "nadac": 0.68, "spread_pct": 5517.6, "tier": "CRITICAL", "estimated_annual_overpayment": 9004.8}, {"drug": "omeprazole 20mg", "quantity": 30, "plan_charge": 72.1, "nadac": 3.14, "spread_pct": 2196.2, "tier": "CRITICAL", "estimated_annual_overpayment": 16550.4}, {"drug": "sertraline 50mg", "quantity": 30, "plan_charge": 64.7, "nadac": 2.14, "spread_pct": 2923.4, "tier": "CRITICAL", "estimated_annual_overpayment": 15014.4}]'::jsonb, 'Recommend immediate transition to Cost Plus Drugs pass-through contract. Estimated 12-month savings: $1.14M.', 1142400.0, NOW() - INTERVAL '1 days');
INSERT INTO reports (report_id, tenant_id, query, summary, drugs_json, recommendation, total_annual_savings, generated_at) VALUES ('rep_a3a792142b7f', 'tenant_costplus', 'Discrepancy analysis for Midwest Logistics — 1,240 self-insured employees, OptumRx contract', 'Midwest Logistics'' OptumRx contract shows tier-CRITICAL spread on 4 of 5 high-volume drugs. Aggregate spread averages 2,650% above NADAC. Modeled annual overpayment: $2,041,800.', '[{"drug": "rosuvastatin 10mg", "quantity": 30, "plan_charge": 142.1, "nadac": 5.77, "spread_pct": 2362.7, "tier": "CRITICAL", "estimated_annual_overpayment": 32719.2}, {"drug": "escitalopram 10mg", "quantity": 30, "plan_charge": 110.5, "nadac": 3.71, "spread_pct": 2878.4, "tier": "CRITICAL", "estimated_annual_overpayment": 25629.6}, {"drug": "pantoprazole 40mg", "quantity": 30, "plan_charge": 98.2, "nadac": 4.72, "spread_pct": 1980.5, "tier": "CRITICAL", "estimated_annual_overpayment": 22435.2}, {"drug": "bupropion XL 150mg", "quantity": 30, "plan_charge": 312.0, "nadac": 10.2, "spread_pct": 2958.8, "tier": "CRITICAL", "estimated_annual_overpayment": 72432.0}, {"drug": "montelukast 10mg", "quantity": 30, "plan_charge": 86.4, "nadac": 2.68, "spread_pct": 3123.9, "tier": "CRITICAL", "estimated_annual_overpayment": 20092.8}]'::jsonb, 'Audit recommended. Cost Plus pass-through transition would save approximately $2.04M annually based on current utilization.', 2041800.0, NOW() - INTERVAL '3 days');
INSERT INTO reports (report_id, tenant_id, query, summary, drugs_json, recommendation, total_annual_savings, generated_at) VALUES ('rep_6b5b1afe3930', 'tenant_costplus', 'PBM spread review for Pacific Tech — 520 employees, Express Scripts contract', 'Pacific Tech''s ESI contract shows HIGH-tier spread across all 5 reviewed drugs. Aggregate spread averages 2,180% above NADAC. Modeled annual overpayment: $743,200.', '[{"drug": "levothyroxine 50mcg", "quantity": 30, "plan_charge": 64.8, "nadac": 4.56, "spread_pct": 1321.1, "tier": "CRITICAL", "estimated_annual_overpayment": 14457.6}, {"drug": "losartan 50mg", "quantity": 30, "plan_charge": 78.2, "nadac": 3.31, "spread_pct": 2262.5, "tier": "CRITICAL", "estimated_annual_overpayment": 17973.6}, {"drug": "amlodipine 5mg", "quantity": 30, "plan_charge": 46.1, "nadac": 1.16, "spread_pct": 3874.1, "tier": "CRITICAL", "estimated_annual_overpayment": 10785.6}, {"drug": "citalopram 20mg", "quantity": 30, "plan_charge": 52.1, "nadac": 1.84, "spread_pct": 2731.5, "tier": "CRITICAL", "estimated_annual_overpayment": 12062.4}, {"drug": "trazodone 50mg", "quantity": 30, "plan_charge": 46.8, "nadac": 1.49, "spread_pct": 3040.9, "tier": "CRITICAL", "estimated_annual_overpayment": 10874.4}]'::jsonb, 'Negotiate pass-through repricing with ESI or transition to Cost Plus. Estimated savings: $743K/year.', 743200.0, NOW() - INTERVAL '5 days');
INSERT INTO reports (report_id, tenant_id, query, summary, drugs_json, recommendation, total_annual_savings, generated_at) VALUES ('rep_5f1f1442fc31', 'tenant_costplus', 'Portfolio analysis: top 50 self-insured prospects derived from Form 5500 filings', '50 self-insured employers analyzed (Form 5500 sourced). Total covered lives: 1.2M. Aggregate estimated annual spread overpayment: $1.498B. Breakdown: OptumRx clients $774M, ESI clients $373M, CVS Caremark clients $351M.', '[{"summary": "Aggregated across 50 self-insured employers in Cost Plus prospect pipeline."}]'::jsonb, 'Top 10 prospects represent $912M in addressable annual savings. Suggested outreach sequence prioritized by overpayment magnitude.', 1498786828.0, NOW() - INTERVAL '7 days');
