INSERT INTO conversations (session_id, tenant_id, messages_json, created_at) VALUES ('sess_856df38d0950', 'tenant_costplus', '[{"role": "user", "content": "What''s the spread on atorvastatin 20mg vs Cost Plus pricing?"}, {"role": "assistant", "content": "Comparing CVS Caremark''s plan-charged price vs Cost Plus and NADAC for atorvastatin 20mg, 30-day supply:\n\n• CVS Caremark plan charge: $86.40\n• NADAC (true acquisition cost): $1.48\n• Cost Plus Drugs price: $4.50\n\nSpread above NADAC: 5,738% (CRITICAL tier)\nCost Plus premium over NADAC: 204% (covers dispensing + transparent margin)\n\nFor a 1,000-employee plan with ~20 monthly atorvastatin fills, switching from Caremark to Cost Plus would save approximately $19,656/year on this drug alone."}]'::jsonb, NOW() - INTERVAL '1 days');
INSERT INTO conversations (session_id, tenant_id, messages_json, created_at) VALUES ('sess_24508319ee0c', 'tenant_costplus', '[{"role": "user", "content": "Pull me the top 10 self-insured prospects with CVS Caremark contracts."}, {"role": "assistant", "content": "Top 10 self-insured Caremark prospects from the Form 5500 dataset (sorted by estimated annual overpayment):\n\n1. Bank of America Corporation — 175,740 employees — est. $54.1M overpayment\n2. Kohl''s, Inc. — 112,420 employees — est. $34.6M overpayment\n3. National Rural Electric Cooperative Association — 71,119 employees — est. $21.9M overpayment\n4. International Business Machines Corporation — 53,360 employees — est. $16.4M overpayment\n5. Trustees of Central States Health & Welfare Fund — 237,668 lives — est. $73.2M overpayment\n6. Lowe''s Companies, Inc. — pending\n7. Marriott International — pending\n8. PepsiCo, Inc. — pending\n9. Disney Worldwide Services — pending\n10. Best Buy Co., Inc. — pending\n\nAggregate estimated overpayment across these 10: ~$240M annually. Want me to draft outreach for any of these accounts?"}]'::jsonb, NOW() - INTERVAL '2 days');
INSERT INTO conversations (session_id, tenant_id, messages_json, created_at) VALUES ('sess_abcd6fef7942', 'tenant_costplus', '[{"role": "user", "content": "Generate a discrepancy report for Acme Manufacturing''s top 5 drugs."}, {"role": "assistant", "content": "Generated report rep_acme_q2_2026. Acme Manufacturing — 850 employees, CVS Caremark contract.\n\nTop 5 drug spread analysis:\n• Atorvastatin 20mg: 5,738% spread above NADAC (CRITICAL)\n• Sertraline 50mg: 2,924% above NADAC (CRITICAL)\n• Omeprazole 20mg: 2,196% above NADAC (CRITICAL)\n• Metformin 500mg: 3,892% above NADAC (CRITICAL)\n• Lisinopril 10mg: 5,517% above NADAC (CRITICAL)\n\nAggregate estimated annual overpayment: $1,142,400.\n\nReport PDF available in your Reports view. Want me to draft the CFO email?"}]'::jsonb, NOW() - INTERVAL '3 days');
INSERT INTO conversations (session_id, tenant_id, messages_json, created_at) VALUES ('sess_acc083314d29', 'tenant_costplus', '[{"role": "user", "content": "How many self-insured employers in our pipeline and what''s the total addressable savings?"}, {"role": "assistant", "content": "Current pipeline (sourced from 2022 Form 5500 filings, refreshed weekly):\n\n• Total qualified prospects: 343 self-insured employers (100+ employees each)\n• Total covered lives: 1.2M\n• Total estimated annual spread overpayment: $1.498 billion\n\nBy PBM:\n• OptumRx clients: 137 employers — $774.4M overpayment\n• Express Scripts clients: 132 employers — $373.3M overpayment\n• CVS Caremark clients: 74 employers — $351.1M overpayment\n\nTop 50 prospects represent $1.2B of the addressable savings. Suggested next step: prioritize outreach to the top 10 by overpayment magnitude."}]'::jsonb, NOW() - INTERVAL '4 days');
